const root = $input.first().json;
const evt = root.body ?? root;
return [{ json: { owner: evt.repository?.owner?.name || evt.repository?.owner?.login || 'OWNER', repo: evt.repository?.name || 'REPOSITORY', branch: String(evt.ref || '').replace('refs/heads/', ''), commits: (evt.commits || []).map(c => ({ id: c.id, message: c.message, added: c.added, modified: c.modified, removed: c.removed })), url: evt.compare } }];

const source = $input.first().json;
let text = String(source.output || source.text || '').trim();
if (!text) text = '## Summary

Automation produced no output. Manual review is required.

## Classification

Unknown

## Recommended Actions
1. Inspect the n8n execution log.
2. Review the source item manually.
3. Re-run the workflow after fixing configuration.

## Evidence
- Empty model response.';
text = text.replace(/@everyone/g, '@​everyone').replace(/@here/g, '@​here');
const MAX = 12000;
if (text.length > MAX) text = text.slice(0, MAX) + '

_Output truncated by workflow before posting._';
return [{ json: { ...source, report: text } }];
